**自定义验证错误信息：**

```go
import "github.com/go-playground/validator/v10"

func formatValidationError(err error) string {
    var ve validator.ValidationErrors
    if errors.As(err, &ve) {
        msgs := make([]string, 0, len(ve))
        for _, e := range ve {
            switch e.Tag() {
            case "required":
                msgs = append(msgs, fmt.Sprintf("%s 是必填项", e.Field()))
            case "email":
                msgs = append(msgs, fmt.Sprintf("%s 格式不正确", e.Field()))
            case "min":
                msgs = append(msgs, fmt.Sprintf("%s 最小值为 %s", e.Field(), e.Param()))
            }
        }
        return strings.Join(msgs, "; ")
    }
    return err.Error()
}
```

**常用 tag 选项：**

```go
type User struct {
    // 基本：重命名 JSON 字段
    ID   int    `json:"id"`
    Name string `json:"name"`

    // omitempty：零值时不输出该字段
    // 零值：0, false, "", nil, 空 slice/map
    Age     int     `json:"age,omitempty"`
    Address *string `json:"address,omitempty"`

    // -：始终忽略该字段（序列化和反序列化都跳过）
    Password string `json:"-"`

    // string：将数字/bool 编码为 JSON 字符串（前端 JS 大数精度问题）
    BigID int64 `json:"big_id,string"` // 输出 "big_id": "9007199254740993"

    // 匿名嵌入：内嵌 struct 的字段提升到外层
    BaseModel // 相当于把 BaseModel 的字段展平

    // 字段名为 "-" 但仍输出：使用 "-,"
    SpecialField string `json:"-,"`
}

type BaseModel struct {
    CreatedAt time.Time `json:"created_at"`
    UpdatedAt time.Time `json:"updated_at"`
}
```

**序列化行为演示：**

```go
user := User{
    ID:   1,
    Name: "Alice",
    Age:  0,         // omitempty：零值，不输出
    // Address: nil  // omitempty：nil，不输出
}

data, _ := json.Marshal(user)
// 输出：{"id":1,"name":"Alice","created_at":"...","updated_at":"..."}
// Age 和 Address 因 omitempty 被省略
```

**常见陷阱：**

```go
// 陷阱1：omitempty 对 struct 类型无效（即使所有字段都是零值，struct 也不是零值）
type Response struct {
    Data   MyStruct `json:"data,omitempty"` // ❌ 不会被省略，struct 不是零值
    DataP  *MyStruct `json:"data_p,omitempty"` // ✅ 指针为 nil 时会被省略
}

// 陷阱2：time.Time 的零值不会被 omitempty 省略（struct 类型）
type Event struct {
    EndTime time.Time `json:"end_time,omitempty"` // ❌ 不起作用
    // 解决：使用 *time.Time
    EndTimeP *time.Time `json:"end_time_p,omitempty"` // ✅
}

// 陷阱3：大写字母开头但无 tag 的字段也会被序列化
type Hidden struct {
    Public  string // 会被序列化为 "Public"
    private string // 未导出，不会被序列化
}
```

**连接池核心参数：**

```go
package main

import (
    "database/sql"
    "time"
    _ "github.com/lib/pq" // PostgreSQL 驱动
)

func newDB(dsn string) (*sql.DB, error) {
    db, err := sql.Open("postgres", dsn)
    if err != nil {
        return nil, err
    }

    // 最大打开连接数（包含空闲+使用中）
    // 0 = 无限制（危险！）
    // 建议：根据数据库最大连接数设置，预留给其他客户端
    db.SetMaxOpenConns(100)

    // 最大空闲连接数（连接池中保持的空闲连接数）
    // 应 <= MaxOpenConns
    // 设置太小：频繁建立/关闭连接；太大：空闲连接浪费资源
    db.SetMaxIdleConns(10)

    // 连接的最大生存时间（从创建起计时）
    // 防止使用长期空闲的连接（数据库服务端可能已关闭）
    // 建议：小于数据库服务端的连接超时（如 MySQL wait_timeout）
    db.SetConnMaxLifetime(30 * time.Minute)

    // 连接的最大空闲时间（连接在池中空闲的最长时间）
    // Go 1.15+ 新增
    // 比 ConnMaxLifetime 更细粒度地控制空闲连接
    db.SetConnMaxIdleTime(10 * time.Minute)

    // 验证连接是否正常
    if err := db.Ping(); err != nil {
        return nil, err
    }

    return db, nil
}
```

**参数关系图：**

```
MaxOpenConns = MaxIdleConns + 使用中的连接数
                    ↑
           空闲连接池（最多 MaxIdleConns 个）

连接生命周期：
  创建 ──[ConnMaxLifetime 超时]──→ 关闭
  空闲 ──[ConnMaxIdleTime 超时]──→ 关闭（即使未达 Lifetime）
```

**监控连接池状态：**

```go
func printDBStats(db *sql.DB) {
    stats := db.Stats()
    fmt.Printf("OpenConnections: %d\n", stats.OpenConnections)
    fmt.Printf("InUse:           %d\n", stats.InUse)
    fmt.Printf("Idle:            %d\n", stats.Idle)
    fmt.Printf("WaitCount:       %d\n", stats.WaitCount)    // 等待连接的次数
    fmt.Printf("WaitDuration:    %v\n", stats.WaitDuration) // 等待总时长
    fmt.Printf("MaxIdleClosed:   %d\n", stats.MaxIdleClosed)   // 因超过 MaxIdle 关闭的连接数
    fmt.Printf("MaxLifetimeClosed: %d\n", stats.MaxLifetimeClosed) // 因 Lifetime 关闭的连接数
}
```

**初始化客户端：**

```go
package main

import (
    "context"
    "fmt"
    "time"

    "github.com/redis/go-redis/v9"
)

var rdb *redis.Client

func initRedis() {
    rdb = redis.NewClient(&redis.Options{
        Addr:     "localhost:6379",
        Password: "", // 无密码留空
        DB:       0,  // 默认 DB

        // 连接池配置
        PoolSize:     10,              // 连接池大小
        MinIdleConns: 3,               // 最小空闲连接
        MaxIdleConns: 5,               // 最大空闲连接
        ConnMaxIdleTime: 5 * time.Minute,
        ConnMaxLifetime: 30 * time.Minute,

        // 超时配置
        DialTimeout:  5 * time.Second,  // 建立连接超时
        ReadTimeout:  3 * time.Second,  // 读超时（-1 = 禁用）
        WriteTimeout: 3 * time.Second,  // 写超时
    })
}

func main() {
    initRedis()
    ctx := context.Background()

    // Ping 测试连接
    if err := rdb.Ping(ctx).Err(); err != nil {
        panic(fmt.Sprintf("redis connect failed: %v", err))
    }

    // 基本操作
    err := rdb.Set(ctx, "key", "value", 10*time.Minute).Err()
    if err != nil {
        fmt.Printf("set error: %v\n", err)
        return
    }

    val, err := rdb.Get(ctx, "key").Result()
    if err == redis.Nil {
        fmt.Println("key not found")
    } else if err != nil {
        fmt.Printf("get error: %v\n", err)
    } else {
        fmt.Printf("key = %s\n", val)
    }

    // Hash 操作
    rdb.HSet(ctx, "user:1", "name", "Alice", "age", 30)
    name, _ := rdb.HGet(ctx, "user:1", "name").Result()
    fmt.Println(name)

    // 带超时的 context
    ctx2, cancel := context.WithTimeout(ctx, 2*time.Second)
    defer cancel()
    rdb.Set(ctx2, "temp", "data", time.Minute)
}
```

