```go
package middleware

import (
    "log/slog"
    "time"

    "github.com/gin-gonic/gin"
    "github.com/google/uuid"
)

const RequestIDKey = "request_id"

// RequestID 中间件：为每个请求注入唯一 ID
func RequestID() gin.HandlerFunc {
    return func(c *gin.Context) {
        // 优先使用客户端传来的 X-Request-ID（便于链路追踪）
        requestID := c.GetHeader("X-Request-ID")
        if requestID == "" {
            requestID = uuid.New().String()
        }
        c.Set(RequestIDKey, requestID)
        c.Header("X-Request-ID", requestID) // 回写到响应头
        c.Next()
    }
}

// Logger 中间件：结构化日志记录
func Logger(logger *slog.Logger) gin.HandlerFunc {
    return func(c *gin.Context) {
        start := time.Now()
        path := c.Request.URL.Path
        query := c.Request.URL.RawQuery

        // 处理请求
        c.Next()

        // 请求结束后记录日志
        latency := time.Since(start)
        statusCode := c.Writer.Status()
        requestID, _ := c.Get(RequestIDKey)

        // 构建结构化日志字段
        attrs := []slog.Attr{
            slog.String("request_id", requestID.(string)),
            slog.String("method", c.Request.Method),
            slog.String("path", path),
            slog.String("query", query),
            slog.Int("status", statusCode),
            slog.Duration("latency", latency),
            slog.String("ip", c.ClientIP()),
            slog.String("user_agent", c.Request.UserAgent()),
            slog.Int("body_size", c.Writer.Size()),
        }

        // 记录 Handler 返回的错误
        if len(c.Errors) > 0 {
            attrs = append(attrs, slog.String("errors", c.Errors.String()))
        }

        // 根据状态码选择日志级别
        level := slog.LevelInfo
        if statusCode >= 500 {
            level = slog.LevelError
        } else if statusCode >= 400 {
            level = slog.LevelWarn
        }

        logger.LogAttrs(c.Request.Context(), level, "HTTP Request", attrs...)
    }
}

// Recovery 中间件：捕获 panic，返回 500 并记录堆栈
func Recovery(logger *slog.Logger) gin.HandlerFunc {
    return func(c *gin.Context) {
        defer func() {
            if err := recover(); err != nil {
                requestID, _ := c.Get(RequestIDKey)
                logger.Error("panic recovered",
                    "request_id", requestID,
                    "error", err,
                    "path", c.Request.URL.Path,
                )
                c.AbortWithStatusJSON(500, gin.H{
                    "code":       500,
                    "message":    "internal server error",
                    "request_id": requestID,
                })
            }
        }()
        c.Next()
    }
}

// 注册中间件
func SetupRouter(logger *slog.Logger) *gin.Engine {
    r := gin.New() // 不使用 gin.Default()（它自带 Logger 和 Recovery）
    r.Use(
        RequestID(),
        Logger(logger),
        Recovery(logger),
    )
    return r
}
```

```go
package auth

import (
    "errors"
    "net/http"
    "strings"
    "time"

    "github.com/gin-gonic/gin"
    "github.com/golang-jwt/jwt/v5"
)

var jwtSecret = []byte("your-secret-key-from-env") // 实际从环境变量读取

// Claims 自定义 JWT Payload
type Claims struct {
    UserID   int64  `json:"user_id"`
    Username string `json:"username"`
    Role     string `json:"role"`
    jwt.RegisteredClaims
}

// GenerateToken 生成 Access Token + Refresh Token
func GenerateTokenPair(userID int64, username, role string) (accessToken, refreshToken string, err error) {
    // Access Token（短有效期）
    accessClaims := &Claims{
        UserID:   userID,
        Username: username,
        Role:     role,
        RegisteredClaims: jwt.RegisteredClaims{
            ExpiresAt: jwt.NewNumericDate(time.Now().Add(15 * time.Minute)),
            IssuedAt:  jwt.NewNumericDate(time.Now()),
            Issuer:    "myapp",
        },
    }
    accessToken, err = jwt.NewWithClaims(jwt.SigningMethodHS256, accessClaims).SignedString(jwtSecret)
    if err != nil {
        return
    }

    // Refresh Token（长有效期，仅含用户 ID）
    refreshClaims := &Claims{
        UserID: userID,
        RegisteredClaims: jwt.RegisteredClaims{
            ExpiresAt: jwt.NewNumericDate(time.Now().Add(7 * 24 * time.Hour)),
            IssuedAt:  jwt.NewNumericDate(time.Now()),
        },
    }
    refreshToken, err = jwt.NewWithClaims(jwt.SigningMethodHS256, refreshClaims).SignedString(jwtSecret)
    return
}

// ParseToken 解析并验证 Token
func ParseToken(tokenStr string) (*Claims, error) {
    token, err := jwt.ParseWithClaims(tokenStr, &Claims{}, func(t *jwt.Token) (interface{}, error) {
        // 验证签名算法（防止 alg=none 攻击）
        if _, ok := t.Method.(*jwt.SigningMethodHMAC); !ok {
            return nil, fmt.Errorf("unexpected signing method: %v", t.Header["alg"])
        }
        return jwtSecret, nil
    })
    if err != nil {
        return nil, err
    }
    claims, ok := token.Claims.(*Claims)
    if !ok || !token.Valid {
        return nil, errors.New("invalid token")
    }
    return claims, nil
}

// JWTAuth Gin 认证中间件
func JWTAuth() gin.HandlerFunc {
    return func(c *gin.Context) {
        // 从 Header 提取 Token
        authHeader := c.GetHeader("Authorization")
        if authHeader == "" {
            c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{
                "code":    401,
                "message": "authorization header required",
            })
            return
        }

        // 格式：Bearer <token>
        parts := strings.SplitN(authHeader, " ", 2)
        if len(parts) != 2 || parts[0] != "Bearer" {
            c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{
                "code":    401,
                "message": "invalid authorization header format",
            })
            return
        }

        claims, err := ParseToken(parts[1])
        if err != nil {
            status := http.StatusUnauthorized
            msg := "invalid token"
            if errors.Is(err, jwt.ErrTokenExpired) {
                msg = "token expired"
            }
            c.AbortWithStatusJSON(status, gin.H{"code": status, "message": msg})
            return
        }

        // 将用户信息写入 context，供后续 Handler 使用
        c.Set("user_id", claims.UserID)
        c.Set("username", claims.Username)
        c.Set("role", claims.Role)
        c.Next()
    }
}

// 获取当前用户 ID 的辅助函数
func CurrentUserID(c *gin.Context) int64 {
    id, _ := c.Get("user_id")
    return id.(int64)
}
```

```go
package middleware

import (
    "net/http"
    "sync"
    "time"

    "github.com/gin-gonic/gin"
    "golang.org/x/time/rate"
)

// ── 方式1：全局限流（所有请求共享一个桶）──────────────────────────────────────

// GlobalRateLimiter 全局令牌桶限流
// r: 每秒补充的令牌数（请求数/秒）
// b: 桶的容量（突发流量上限）
func GlobalRateLimiter(r rate.Limit, b int) gin.HandlerFunc {
    limiter := rate.NewLimiter(r, b)
    return func(c *gin.Context) {
        if !limiter.Allow() {
            c.AbortWithStatusJSON(http.StatusTooManyRequests, gin.H{
                "code":    429,
                "message": "rate limit exceeded, please retry later",
            })
            return
        }
        c.Next()
    }
}

// ── 方式2：按 IP 限流（每个 IP 独立令牌桶）──────────────────────────────────

type IPRateLimiter struct {
    mu       sync.Mutex
    limiters map[string]*entry
    r        rate.Limit
    b        int
    ttl      time.Duration // 不活跃 IP 的清理时间
}

type entry struct {
    limiter  *rate.Limiter
    lastSeen time.Time
}

func NewIPRateLimiter(r rate.Limit, b int) *IPRateLimiter {
    rl := &IPRateLimiter{
        limiters: make(map[string]*entry),
        r:        r,
        b:        b,
        ttl:      10 * time.Minute,
    }
    go rl.cleanup() // 定期清理过期 IP
    return rl
}

func (rl *IPRateLimiter) getLimiter(ip string) *rate.Limiter {
    rl.mu.Lock()
    defer rl.mu.Unlock()

    e, ok := rl.limiters[ip]
    if !ok {
        e = &entry{limiter: rate.NewLimiter(rl.r, rl.b)}
        rl.limiters[ip] = e
    }
    e.lastSeen = time.Now()
    return e.limiter
}

func (rl *IPRateLimiter) cleanup() {
    ticker := time.NewTicker(rl.ttl)
    defer ticker.Stop()
    for range ticker.C {
        rl.mu.Lock()
        for ip, e := range rl.limiters {
            if time.Since(e.lastSeen) > rl.ttl {
                delete(rl.limiters, ip)
            }
        }
        rl.mu.Unlock()
    }
}

// IPRateLimit Gin 中间件
func IPRateLimit(r rate.Limit, b int) gin.HandlerFunc {
    limiter := NewIPRateLimiter(r, b)
    return func(c *gin.Context) {
        ip := c.ClientIP()
        if !limiter.getLimiter(ip).Allow() {
            c.Header("Retry-After", "1")
            c.AbortWithStatusJSON(http.StatusTooManyRequests, gin.H{
                "code":    429,
                "message": "too many requests from your IP",
            })
            return
        }
        c.Next()
    }
}

// 使用示例
func SetupRoutes(r *gin.Engine) {
    // 全局：每秒 1000 请求，突发 2000
    r.Use(GlobalRateLimiter(1000, 2000))

    api := r.Group("/api")
    // 登录接口单独限流：每 IP 每秒 5 次，防暴力破解
    api.POST("/login", IPRateLimit(5, 10), loginHandler)
}
