**N+1 问题的产生：**

```go
// 假设查询 10 个用户及其订单
// ❌ N+1：先查 1 次用户列表，再对每个用户查 1 次订单，共 11 次 SQL
var users []User
db.Find(&users) // SQL: SELECT * FROM users → 返回 10 条

for _, user := range users {
    var orders []Order
    db.Where("user_id = ?", user.ID).Find(&orders) // 每次循环 1 条 SQL
    user.Orders = orders
}
// 总计 11 条 SQL！用户越多，问题越严重
```

**解决方案一：`Preload`（推荐，分 2 次 SQL）**

```go
type User struct {
    ID     uint
    Name   string
    Orders []Order `gorm:"foreignKey:UserID"`
}

type Order struct {
    ID     uint
    UserID uint
    Amount float64
    Items  []OrderItem `gorm:"foreignKey:OrderID"`
}

// ✅ Preload：2 条 SQL（IN 查询）
var users []User
db.Preload("Orders").Find(&users)
// SQL 1: SELECT * FROM users
// SQL 2: SELECT * FROM orders WHERE user_id IN (1,2,3,...)

// 多级预加载
db.Preload("Orders.Items").Find(&users)
// SQL 1: SELECT * FROM users
// SQL 2: SELECT * FROM orders WHERE user_id IN (...)
// SQL 3: SELECT * FROM order_items WHERE order_id IN (...)

// 带条件的预加载
db.Preload("Orders", "status = ?", "paid").Find(&users)
// SQL 2: SELECT * FROM orders WHERE user_id IN (...) AND status = 'paid'

// 使用闭包自定义预加载查询
db.Preload("Orders", func(db *gorm.DB) *gorm.DB {
    return db.Order("created_at DESC").Limit(5) // 每个用户最近 5 个订单
}).Find(&users)
```

**解决方案二：`Joins`（1 条 SQL，适合需要过滤关联数据的场景）**

```go
// Joins：使用 JOIN 语句，返回扁平化结果
var users []User
db.Joins("Orders").Find(&users)
// SQL: SELECT users.*, orders.* FROM users LEFT JOIN orders ON orders.user_id = users.id

// 基于关联条件过滤主表
db.Joins("JOIN orders ON orders.user_id = users.id AND orders.amount > ?", 100).
    Distinct().
    Find(&users)
// 查找有金额>100订单的用户
```

**对比选择：**

| 场景             | 推荐方式                      |
| ---------------- | ----------------------------- |
| 关联数据完整加载 | `Preload`                     |
| 基于关联条件过滤 | `Joins`                       |
| 大量数据聚合查询 | 手写 SQL + `Scan`             |
| 性能极致场景     | `Select` 指定字段 + `Preload` |

```go
package service

import (
    "context"
    "fmt"

    "gorm.io/gorm"
)

type OrderService struct {
    db *gorm.DB
}

// ── 方式1：Transaction 闭包（推荐，自动提交/回滚）───────────────────────────

func (s *OrderService) CreateOrder(ctx context.Context, order *Order) error {
    return s.db.WithContext(ctx).Transaction(func(tx *gorm.DB) error {
        // 1. 扣减库存
        result := tx.Model(&Product{}).
            Where("id = ? AND stock >= ?", order.ProductID, order.Quantity).
            Update("stock", gorm.Expr("stock - ?", order.Quantity))

        if result.Error != nil {
            return result.Error // 返回 error 自动触发回滚
        }
        if result.RowsAffected == 0 {
            return fmt.Errorf("insufficient stock for product %d", order.ProductID)
        }

        // 2. 创建订单记录
        if err := tx.Create(order).Error; err != nil {
            return err // 返回 error 自动触发回滚
        }

        // 3. 记录库存变更日志
        log := &StockLog{
            ProductID: order.ProductID,
            Delta:     -order.Quantity,
            OrderID:   order.ID,
        }
        if err := tx.Create(log).Error; err != nil {
            return err
        }

        return nil // 返回 nil 自动提交
    })
}

// ── 方式2：手动事务（需要跨函数传递 tx 时使用）──────────────────────────────

func (s *OrderService) TransferBalance(ctx context.Context, fromID, toID int64, amount float64) error {
    tx := s.db.WithContext(ctx).Begin()
    if tx.Error != nil {
        return fmt.Errorf("begin transaction: %w", tx.Error)
    }

    // defer 确保异常时也能回滚
    defer func() {
        if r := recover(); r != nil {
            tx.Rollback()
            panic(r) // 重新 panic，让上层处理
        }
    }()

    // 扣减转出账户
    if err := tx.Model(&Account{}).
        Where("id = ? AND balance >= ?", fromID, amount).
        Update("balance", gorm.Expr("balance - ?", amount)).Error; err != nil {
        tx.Rollback()
        return fmt.Errorf("deduct from account %d: %w", fromID, err)
    }

    // 增加转入账户
    if err := tx.Model(&Account{}).
        Where("id = ?", toID).
        Update("balance", gorm.Expr("balance + ?", amount)).Error; err != nil {
        tx.Rollback()
        return fmt.Errorf("add to account %d: %w", toID, err)
    }

    // 提交事务
    if err := tx.Commit().Error; err != nil {
        return fmt.Errorf("commit transaction: %w", err)
    }
    return nil
}

// ── 方式3：SavePoint（嵌套事务）─────────────────────────────────────────────

func nestedTransaction(db *gorm.DB) error {
    return db.Transaction(func(tx *gorm.DB) error {
        tx.Create(&User{Name: "Alice"})

        // 嵌套事务（使用 Savepoint）
        if err := tx.Transaction(func(tx2 *gorm.DB) error {
            tx2.Create(&User{Name: "Bob"})
            return errors.New("rollback inner only") // 只回滚内层
        }); err != nil {
            // 内层回滚，但外层继续
        }

        tx.Create(&User{Name: "Charlie"})
        return nil // Alice 和 Charlie 提交，Bob 被回滚
    })
}
```

**三种问题定义：**

| 问题         | 触发场景                                         | 后果                     |
| ------------ | ------------------------------------------------ | ------------------------ |
| **缓存穿透** | 查询**不存在**的数据（既没有缓存也没有 DB 数据） | 每次都打到 DB，DB 压力大 |
| **缓存击穿** | **热点 key 过期**的瞬间，大量请求同时涌入        | 瞬间 DB 压力爆炸         |
| **缓存雪崩** | 大量 key **同时过期**或 Redis 宕机               | DB 被大量请求压垮        |

**缓存穿透 → 布隆过滤器 + 缓存空值：**

```go
// 方案1：缓存空值（简单有效）
func (s *UserService) GetUser(ctx context.Context, id int64) (*User, error) {
    cacheKey := fmt.Sprintf("user:%d", id)

    // 查 Redis
    val, err := s.rdb.Get(ctx, cacheKey).Bytes()
    if err == nil {
        if string(val) == "null" {
            return nil, ErrNotFound // 缓存了空值，直接返回 404
        }
        var user User
        json.Unmarshal(val, &user)
        return &user, nil
    }

    // Redis miss，查 DB
    user, err := s.repo.GetUser(ctx, id)
    if err != nil {
        if errors.Is(err, ErrNotFound) {
            // 缓存空值，防止穿透（短 TTL 防止合法数据恢复后延迟过长）
            s.rdb.Set(ctx, cacheKey, "null", 5*time.Minute)
        }
        return nil, err
    }

    data, _ := json.Marshal(user)
    s.rdb.Set(ctx, cacheKey, data, 30*time.Minute)
    return user, nil
}
```

**缓存击穿 → singleflight 防并发重建：**

```go
import "golang.org/x/sync/singleflight"

type UserService struct {
    rdb *redis.Client
    sf  singleflight.Group // 关键：相同 key 只执行一次 DB 查询
}

func (s *UserService) GetHotUser(ctx context.Context, id int64) (*User, error) {
    cacheKey := fmt.Sprintf("user:%d", id)

    // 先查缓存
    if val, err := s.rdb.Get(ctx, cacheKey).Bytes(); err == nil {
        var user User
        json.Unmarshal(val, &user)
        return &user, nil
    }

    // singleflight：同一 key 的并发请求只执行一次
    v, err, _ := s.sf.Do(cacheKey, func() (interface{}, error) {
        // 再查一次缓存（可能上一个请求已经写入）
        if val, err := s.rdb.Get(ctx, cacheKey).Bytes(); err == nil {
            var user User
            json.Unmarshal(val, &user)
            return &user, nil
        }
        // 查 DB
        user, err := s.repo.GetUser(ctx, id)
        if err != nil { return nil, err }
        data, _ := json.Marshal(user)
        s.rdb.Set(ctx, cacheKey, data, 30*time.Minute)
        return user, nil
    })
    if err != nil { return nil, err }
    return v.(*User), nil
}
```

**缓存雪崩 → 随机 TTL + 多级缓存 + 熔断：**

```go
import (
    "math/rand"
)

// 随机化 TTL，防止同时过期
func randomTTL(base time.Duration) time.Duration {
    // 在 base ±20% 范围内随机
    jitter := time.Duration(rand.Int63n(int64(base) / 5))
    return base + jitter
}

// 使用：
s.rdb.Set(ctx, key, data, randomTTL(30*time.Minute))

// 其他手段：
// 1. 永不过期 + 异步更新（后台 goroutine 定期刷新）
// 2. 双重缓存（本地 LRU + Redis）
// 3. Redis 集群 + 哨兵，防单点故障
// 4. 熔断降级（hystrix-go、go-sentinel）
```

**基础实现：`SET key value NX PX ttl`**

```go
package lock

import (
    "context"
    "errors"
    "fmt"
    "time"

    "github.com/redis/go-redis/v9"
    "github.com/google/uuid"
)

var ErrLockNotAcquired = errors.New("lock not acquired")

type RedisLock struct {
    rdb   *redis.Client
    key   string
    value string        // 随机值，用于防止误删
    ttl   time.Duration
}

// TryLock 尝试获取锁（非阻塞）
func TryLock(ctx context.Context, rdb *redis.Client, key string, ttl time.Duration) (*RedisLock, error) {
    value := uuid.New().String() // 唯一标识，防止锁被其他实例释放

    // SET key value NX PX milliseconds
    // NX: 仅当 key 不存在时设置
    // PX: 过期时间（毫秒），防止死锁
    ok, err := rdb.SetNX(ctx, key, value, ttl).Result()
    if err != nil {
        return nil, fmt.Errorf("redis setnx: %w", err)
    }
    if !ok {
        return nil, ErrLockNotAcquired
    }
    return &RedisLock{rdb: rdb, key: key, value: value, ttl: ttl}, nil
}

// Unlock 释放锁（使用 Lua 脚本保证原子性）
func (l *RedisLock) Unlock(ctx context.Context) error {
    // ❌ 错误方式：GET + DEL 两步操作，非原子，可能误删其他实例的锁
    // val, _ := rdb.Get(ctx, key).Result()
    // if val == l.value { rdb.Del(ctx, key) }

    // ✅ 正确方式：Lua 脚本原子执行 GET + DEL
    const luaScript = `
        if redis.call("GET", KEYS[1]) == ARGV[1] then
            return redis.call("DEL", KEYS[1])
        else
            return 0
        end
    `
    result, err := l.rdb.Eval(ctx, luaScript, []string{l.key}, l.value).Int()
    if err != nil {
        return fmt.Errorf("unlock lua: %w", err)
    }
    if result == 0 {
        return errors.New("lock already expired or held by another instance")
    }
    return nil
}

// 使用示例
func ProcessOrder(ctx context.Context, rdb *redis.Client, orderID int64) error {
    lockKey := fmt.Sprintf("lock:order:%d", orderID)

    lock, err := TryLock(ctx, rdb, lockKey, 30*time.Second)
    if errors.Is(err, ErrLockNotAcquired) {
        return errors.New("order is being processed by another instance")
    }
    if err != nil {
        return err
    }
    defer lock.Unlock(ctx)

    // 处理订单（在锁保护下执行）
    return doProcessOrder(ctx, orderID)
}
```

**`SET NX` vs Lua 脚本的区别：**

| 操作                      | 原子性          | 适用场景            |
| ------------------------- | --------------- | ------------------- |
| `SET key val NX PX ttl`   | ✅ 原子（加锁） | 获取锁（推荐）      |
| `GET` + `DEL`（两条命令） | ❌ 非原子       | ❌ 不要用于释放锁   |
| Lua 脚本（GET+DEL）       | ✅ 原子         | ✅ 释放锁的正确方式 |

