```go
package interceptor

import (
    "context"
    "log/slog"
    "strings"
    "time"

    "google.golang.org/grpc"
    "google.golang.org/grpc/codes"
    "google.golang.org/grpc/metadata"
    "google.golang.org/grpc/status"
)

// ── 服务端拦截器 ───────────────────────────────────────────────────────────

// LoggingInterceptor 日志记录拦截器（Unary）
func LoggingInterceptor(logger *slog.Logger) grpc.UnaryServerInterceptor {
    return func(
        ctx context.Context,
        req interface{},
        info *grpc.UnaryServerInfo,
        handler grpc.UnaryHandler,
    ) (interface{}, error) {
        start := time.Now()

        // 调用实际 Handler
        resp, err := handler(ctx, req)

        // 记录日志
        logger.Info("gRPC request",
            "method", info.FullMethod,
            "duration", time.Since(start),
            "error", err,
        )
        return resp, err
    }
}

// AuthInterceptor JWT 认证拦截器（Unary）
func AuthInterceptor(jwtSecret string) grpc.UnaryServerInterceptor {
    // 不需要认证的方法白名单
    whitelist := map[string]bool{
        "/user.v1.UserService/Login":    true,
        "/user.v1.UserService/Register": true,
    }

    return func(
        ctx context.Context,
        req interface{},
        info *grpc.UnaryServerInfo,
        handler grpc.UnaryHandler,
    ) (interface{}, error) {
        if whitelist[info.FullMethod] {
            return handler(ctx, req)
        }

        // 从 metadata 提取 token
        md, ok := metadata.FromIncomingContext(ctx)
        if !ok {
            return nil, status.Error(codes.Unauthenticated, "missing metadata")
        }

        tokens := md.Get("authorization")
        if len(tokens) == 0 {
            return nil, status.Error(codes.Unauthenticated, "missing token")
        }

        tokenStr := strings.TrimPrefix(tokens[0], "Bearer ")
        claims, err := parseJWT(tokenStr, jwtSecret)
        if err != nil {
            return nil, status.Error(codes.Unauthenticated, "invalid token")
        }

        // 将用户信息注入 context
        ctx = context.WithValue(ctx, contextKeyUserID, claims.UserID)
        return handler(ctx, req)
    }
}

// ── 链式拦截器（服务端）──────────────────────────────────────────────────────

func NewGRPCServer(logger *slog.Logger, secret string) *grpc.Server {
    return grpc.NewServer(
        grpc.ChainUnaryInterceptor(
            RecoveryInterceptor(), // panic 恢复（最外层）
            LoggingInterceptor(logger),
            AuthInterceptor(secret),
        ),
        grpc.ChainStreamInterceptor(
            StreamLoggingInterceptor(logger),
        ),
    )
}

// ── 客户端拦截器 ───────────────────────────────────────────────────────────

// ClientAuthInterceptor 客户端自动注入 token
func ClientAuthInterceptor(tokenFunc func() string) grpc.UnaryClientInterceptor {
    return func(
        ctx context.Context,
        method string,
        req, reply interface{},
        cc *grpc.ClientConn,
        invoker grpc.UnaryInvoker,
        opts ...grpc.CallOption,
    ) error {
        // 将 token 注入 metadata
        ctx = metadata.AppendToOutgoingContext(ctx,
            "authorization", "Bearer "+tokenFunc(),
        )
        return invoker(ctx, method, req, reply, cc, opts...)
    }
}

// 客户端连接
func NewGRPCClient(addr string, getToken func() string) (*grpc.ClientConn, error) {
    return grpc.Dial(addr,
        grpc.WithInsecure(),
        grpc.WithChainUnaryInterceptor(
            ClientAuthInterceptor(getToken),
        ),
    )
}
