```go
package httpclient

import (
    "bytes"
    "context"
    "encoding/json"
    "fmt"
    "io"
    "net"
    "net/http"
    "time"
)

// Client 封装了生产级 HTTP 客户端
type Client struct {
    httpClient *http.Client
    baseURL    string
    maxRetries int
    retryWait  time.Duration
}

// NewClient 创建带连接池和超时配置的 HTTP 客户端
func NewClient(baseURL string, opts ...Option) *Client {
    transport := &http.Transport{
        // 连接池配置
        MaxIdleConns:        100,              // 所有 host 的最大空闲连接总数
        MaxIdleConnsPerHost: 10,               // 每个 host 的最大空闲连接数（默认只有 2！）
        MaxConnsPerHost:     50,               // 每个 host 的最大连接数（0=不限制）
        IdleConnTimeout:     90 * time.Second, // 空闲连接超时

        // TLS 和连接配置
        TLSHandshakeTimeout:   10 * time.Second,
        ResponseHeaderTimeout: 10 * time.Second, // 等待响应头的超时
        ExpectContinueTimeout: 1 * time.Second,

        // 保持长连接
        DisableKeepAlives: false,

        // DNS 缓存（通过自定义 Dialer）
        DialContext: (&net.Dialer{
            Timeout:   30 * time.Second, // TCP 连接超时
            KeepAlive: 30 * time.Second, // TCP KeepAlive 间隔
        }).DialContext,
    }

    c := &Client{
        httpClient: &http.Client{
            Transport: transport,
            Timeout:   30 * time.Second, // 整个请求（含读取 body）的超时
        },
        baseURL:    baseURL,
        maxRetries: 3,
        retryWait:  500 * time.Millisecond,
    }

    for _, opt := range opts {
        opt(c)
    }
    return c
}

// Do 执行请求，支持自动重试（幂等方法）
func (c *Client) Do(ctx context.Context, method, path string, body interface{}) (*http.Response, error) {
    var bodyBytes []byte
    if body != nil {
        var err error
        bodyBytes, err = json.Marshal(body)
        if err != nil {
            return nil, fmt.Errorf("marshal request body: %w", err)
        }
    }

    var lastErr error
    for attempt := 0; attempt <= c.maxRetries; attempt++ {
        if attempt > 0 {
            // 指数退避
            wait := c.retryWait * time.Duration(1<<uint(attempt-1))
            select {
            case <-ctx.Done():
                return nil, ctx.Err()
            case <-time.After(wait):
            }
        }

        req, err := http.NewRequestWithContext(ctx, method, c.baseURL+path,
            bytes.NewReader(bodyBytes))
        if err != nil {
            return nil, err
        }
        req.Header.Set("Content-Type", "application/json")

        resp, err := c.httpClient.Do(req)
        if err != nil {
            lastErr = err
            // 连接错误可以重试
            if isRetryableError(err) && isIdempotent(method) {
                continue
            }
            return nil, err
        }

        // 5xx 服务端错误可以重试（GET/HEAD 等幂等方法）
        if resp.StatusCode >= 500 && isIdempotent(method) && attempt < c.maxRetries {
            resp.Body.Close()
            lastErr = fmt.Errorf("server error: %d", resp.StatusCode)
            continue
        }

        return resp, nil
    }
    return nil, fmt.Errorf("all %d retries failed: %w", c.maxRetries+1, lastErr)
}

// Get 便捷方法
func (c *Client) GetJSON(ctx context.Context, path string, result interface{}) error {
    resp, err := c.Do(ctx, http.MethodGet, path, nil)
    if err != nil {
        return err
    }
    defer resp.Body.Close()

    if resp.StatusCode != http.StatusOK {
        body, _ := io.ReadAll(io.LimitReader(resp.Body, 1024))
        return fmt.Errorf("unexpected status %d: %s", resp.StatusCode, body)
    }

    return json.NewDecoder(resp.Body).Decode(result)
}

func isRetryableError(err error) bool {
    if netErr, ok := err.(net.Error); ok {
        return netErr.Timeout() || netErr.Temporary()
    }
    return false
}

func isIdempotent(method string) bool {
    switch method {
    case http.MethodGet, http.MethodHead, http.MethodOptions, http.MethodPut, http.MethodDelete:
        return true
    }
    return false
}

type Option func(*Client)

func WithTimeout(d time.Duration) Option {
    return func(c *Client) { c.httpClient.Timeout = d }
}

func WithMaxRetries(n int) Option {
    return func(c *Client) { c.maxRetries = n }
}
