**Protobuf 定义：**

```protobuf
syntax = "proto3";
package notification.v1;
option go_package = "myapp/gen/notification/v1;notificationv1";

service NotificationService {
  // 服务端流式 RPC：客户端发一个请求，服务端持续推送
  rpc Subscribe(SubscribeRequest) returns (stream Notification);

  // 双向流式 RPC：客户端和服务端都可以持续发送
  rpc Chat(stream ChatMessage) returns (stream ChatMessage);
}

message SubscribeRequest {
  string user_id = 1;
  repeated string topics = 2; // 订阅的主题列表
}

message Notification {
  string id      = 1;
  string topic   = 2;
  string content = 3;
  int64  timestamp = 4;
}
