**服务端实现：**

```go
package service

import (
    "context"
    "fmt"
    "time"

    "google.golang.org/grpc/codes"
    "google.golang.org/grpc/status"

    pb "myapp/gen/notification/v1"
)

type NotificationServer struct {
    pb.UnimplementedNotificationServiceServer
    broker *MessageBroker // 消息代理（pub/sub）
}

// Subscribe 服务端流式实现
func (s *NotificationServer) Subscribe(
    req *pb.SubscribeRequest,
    stream pb.NotificationService_SubscribeServer,
) error {
    userID := req.UserId
    ctx := stream.Context()

    // 订阅消息（返回一个 channel）
    ch, unsubscribe := s.broker.Subscribe(userID, req.Topics)
    defer unsubscribe() // 确保取消订阅，释放资源

    fmt.Printf("user %s subscribed to topics: %v\n", userID, req.Topics)

    for {
        select {
        case <-ctx.Done():
            // 客户端断开连接
            fmt.Printf("user %s disconnected: %v\n", userID, ctx.Err())
            return nil

        case msg, ok := <-ch:
            if !ok {
                // broker 关闭了 channel
                return status.Error(codes.Unavailable, "notification service shutting down")
            }

            notification := &pb.Notification{
                Id:        msg.ID,
                Topic:     msg.Topic,
                Content:   msg.Content,
                Timestamp: time.Now().UnixMilli(),
            }

            // 向客户端发送消息
            if err := stream.Send(notification); err != nil {
                // 发送失败（客户端已断开）
                fmt.Printf("send to %s failed: %v\n", userID, err)
                return err
            }
        }
    }
}

// ── 客户端实现 ─────────────────────────────────────────────────────────────

func SubscribeNotifications(conn *grpc.ClientConn, userID string, topics []string) error {
    client := pb.NewNotificationServiceClient(conn)

    ctx, cancel := context.WithCancel(context.Background())
    defer cancel()

    stream, err := client.Subscribe(ctx, &pb.SubscribeRequest{
        UserId: userID,
        Topics: topics,
    })
    if err != nil {
        return fmt.Errorf("subscribe: %w", err)
    }

    for {
        notification, err := stream.Recv()
        if err == io.EOF {
            fmt.Println("stream closed by server")
            return nil
        }
        if err != nil {
            // 检查是否是 context 取消
            if status.Code(err) == codes.Canceled {
                return nil
            }
            return fmt.Errorf("recv: %w", err)
        }
        fmt.Printf("[%s] %s: %s\n", notification.Topic, notification.Id, notification.Content)
    }
}
