**熔断器状态机：**

```
              失败率 >= 阈值
  Closed ──────────────────→ Open
    ↑                           │
    │ 成功                      │ 等待重置时间
    │         Half-Open ←───────┘
    └──────────────────
         试探成功
```

**手写熔断器实现：**

```go
package breaker

import (
    "errors"
    "sync"
    "time"
)

var ErrCircuitOpen = errors.New("circuit breaker is open")

type State int

const (
    StateClosed   State = iota // 正常，请求通过
    StateHalfOpen              // 半开，允许试探请求
    StateOpen                  // 熔断，拒绝所有请求
)

type CircuitBreaker struct {
    mu sync.Mutex

    state State

    // Closed 状态计数
    failureCount   int
    successCount   int
    failureThreshold int // 连续失败次数触发熔断

    // Open 状态计时
    openedAt     time.Time
    resetTimeout time.Duration // 等待多久后进入 HalfOpen

    // HalfOpen 状态配置
    halfOpenMaxRequests int // 半开状态允许的最大试探请求数
    halfOpenRequests    int
}

func New(failureThreshold int, resetTimeout time.Duration) *CircuitBreaker {
    return &CircuitBreaker{
        failureThreshold:    failureThreshold,
        resetTimeout:        resetTimeout,
        halfOpenMaxRequests: 1,
    }
}

// Allow 判断当前请求是否允许通过
func (cb *CircuitBreaker) Allow() (func(success bool), error) {
    cb.mu.Lock()
    defer cb.mu.Unlock()

    switch cb.state {
    case StateOpen:
        // 检查是否到了重置时间
        if time.Since(cb.openedAt) >= cb.resetTimeout {
            cb.setState(StateHalfOpen)
            // 允许一个试探请求通过
        } else {
            return nil, ErrCircuitOpen
        }
        fallthrough

    case StateHalfOpen:
        if cb.halfOpenRequests >= cb.halfOpenMaxRequests {
            return nil, ErrCircuitOpen
        }
        cb.halfOpenRequests++

    case StateClosed:
        // 正常通过
    }

    // 返回回调函数，在请求结束后调用
    done := func(success bool) {
        cb.mu.Lock()
        defer cb.mu.Unlock()
        cb.record(success)
    }
    return done, nil
}

func (cb *CircuitBreaker) record(success bool) {
    switch cb.state {
    case StateClosed:
        if success {
            cb.failureCount = 0 // 成功重置失败计数
        } else {
            cb.failureCount++
            if cb.failureCount >= cb.failureThreshold {
                cb.setState(StateOpen)
            }
        }

    case StateHalfOpen:
        cb.halfOpenRequests--
        if success {
            cb.setState(StateClosed) // 试探成功，关闭熔断
        } else {
            cb.setState(StateOpen) // 试探失败，重新熔断
        }
    }
}

func (cb *CircuitBreaker) setState(s State) {
    cb.state = s
    switch s {
    case StateOpen:
        cb.openedAt = time.Now()
    case StateClosed:
        cb.failureCount = 0
        cb.successCount = 0
    case StateHalfOpen:
        cb.halfOpenRequests = 0
    }
}

// Execute 封装请求执行（推荐使用）
func (cb *CircuitBreaker) Execute(fn func() error) error {
    done, err := cb.Allow()
    if err != nil {
        return err // 熔断，直接返回降级
    }

    err = fn()
    done(err == nil)
    return err
}

// 使用示例
func callExternalService(cb *CircuitBreaker, userID int) (*User, error) {
    var user *User
    err := cb.Execute(func() error {
        var err error
        user, err = externalAPI.GetUser(userID) // 可能失败的外部调用
        return err
    })

    if errors.Is(err, ErrCircuitOpen) {
        // 降级处理：返回缓存数据或默认值
        return getFromCache(userID), nil
    }
    return user, err
}
```

