**常见瓶颈与优化手段：**

**瓶颈1：JSON 序列化的内存分配**

```go
// ❌ 每次请求都分配新 buffer
func handler(w http.ResponseWriter, r *http.Request) {
    data, _ := json.Marshal(response) // 分配 []byte
    w.Write(data)
}

// ✅ 使用 sync.Pool 复用 buffer
var encoderPool = sync.Pool{
    New: func() interface{} {
        return &bytes.Buffer{}
    },
}

func handlerV2(w http.ResponseWriter, r *http.Request) {
    buf := encoderPool.Get().(*bytes.Buffer)
    defer func() {
        buf.Reset()
        encoderPool.Put(buf)
    }()

    json.NewEncoder(buf).Encode(response)
    w.Header().Set("Content-Type", "application/json")
    // io.Copy 零拷贝写入 ResponseWriter
    io.Copy(w, buf)
}
```

**瓶颈2：`io.ReadAll` 读取 Body 的重复分配**

```go
// ❌ 每次都分配新 slice
body, _ := io.ReadAll(r.Body)

// ✅ 复用 buffer，限制读取大小（防止 OOM）
var bodyPool = sync.Pool{
    New: func() interface{} {
        buf := make([]byte, 0, 32*1024) // 32KB 初始容量
        return &buf
    },
}

func readBody(r *http.Request) ([]byte, error) {
    if r.ContentLength > 10*1024*1024 { // 拒绝超过 10MB 的请求
        return nil, errors.New("request body too large")
    }

    bufPtr := bodyPool.Get().(*[]byte)
    defer func() {
        *bufPtr = (*bufPtr)[:0]
        bodyPool.Put(bufPtr)
    }()

    buf := *bufPtr
    buf, err := io.ReadAll(io.LimitReader(r.Body, 10*1024*1024))
    return buf, err
}
```

**瓶颈3：HTTP 客户端连接未复用（忘记 Close Body）**

```go
// ❌ 忘记读取并关闭 Body，导致连接无法复用
resp, err := http.Get(url)
if err != nil { return err }
defer resp.Body.Close() // ✅ 必须关闭

// ✅ 正确方式：读取完整 body 后关闭
resp, err := http.Get(url)
if err != nil { return err }
defer func() {
    io.Copy(io.Discard, resp.Body) // 确保 body 被完全读取
    resp.Body.Close()
}()
```

**瓶颈4：string ↔ []byte 的频繁转换**

```go
