package middleware

import (
    "context"
    "net/http"
    "sync"
    "time"

    "github.com/gin-gonic/gin"
)

// Timeout 请求超时中间件
// 超时后向客户端返回 504，并取消后续处理
func Timeout(timeout time.Duration) gin.HandlerFunc {
    return func(c *gin.Context) {
        // 创建带超时的 context
        ctx, cancel := context.WithTimeout(c.Request.Context(), timeout)
        defer cancel()

        // 替换 request 中的 context
        c.Request = c.Request.WithContext(ctx)

        // 用 channel 同步 Handler 完成信号
        done := make(chan struct{}, 1)

        // 使用自定义 ResponseWriter 防止超时后写入
        tw := &timeoutWriter{
            ResponseWriter: c.Writer,
            mu:             &sync.Mutex{},
        }
        c.Writer = tw

        go func() {
            c.Next()
            done <- struct{}{}
        }()

        select {
        case <-done:
            // Handler 正常完成
            return

        case <-ctx.Done():
            // 超时：标记 writer 为已超时，防止后续写入
            tw.mu.Lock()
            tw.timedOut = true
            tw.mu.Unlock()

            // 若响应还未写入，返回 504
            if !tw.written {
                c.AbortWithStatusJSON(http.StatusGatewayTimeout, gin.H{
                    "code":    504,
                    "message": "request timeout",
                })
            }
        }
    }
}

// timeoutWriter 包装 gin.ResponseWriter，超时后拦截写入操作
type timeoutWriter struct {
    gin.ResponseWriter
    mu       *sync.Mutex
    timedOut bool
    written  bool
}

func (tw *timeoutWriter) WriteHeader(code int) {
    tw.mu.Lock()
    defer tw.mu.Unlock()
    if tw.timedOut {
        return // 超时后忽略写入，防止 superfluous response.WriteHeader call
    }
    tw.written = true
    tw.ResponseWriter.WriteHeader(code)
}

func (tw *timeoutWriter) Write(b []byte) (int, error) {
    tw.mu.Lock()
    defer tw.mu.Unlock()
    if tw.timedOut {
        return 0, nil // 超时后忽略写入，防止 panic
    }
    tw.written = true
    return tw.ResponseWriter.Write(b)
}

func (tw *timeoutWriter) WriteString(s string) (int, error) {
    tw.mu.Lock()
    defer tw.mu.Unlock()
    if tw.timedOut {
        return 0, nil
    }
    tw.written = true
    return tw.ResponseWriter.WriteString(s)
}

// 使用示例
func SetupRouter() *gin.Engine {
    r := gin.New()
    r.Use(
        Timeout(10*time.Second), // 全局 10 秒超时
    )

    // 个别路由覆盖超时
    slowGroup := r.Group("/slow")
    slowGroup.Use(Timeout(60 * time.Second)) // 慢接口允许更长时间
    {
        slowGroup.GET("/report", generateReportHandler)
    }

    return r
}
