package database

import (
    "math/rand"
    "sync/atomic"

    "gorm.io/driver/mysql"
    "gorm.io/gorm"
    "gorm.io/gorm/logger"
    "gorm.io/plugin/dbresolver"
)

// ── 方式1：使用 GORM 官方 dbresolver 插件（推荐）──────────────────────────

func NewDBWithResolver(masterDSN string, replicaDSNs []string) (*gorm.DB, error) {
    db, err := gorm.Open(mysql.Open(masterDSN), &gorm.Config{
        Logger: logger.Default.LogMode(logger.Info),
    })
    if err != nil {
        return nil, err
    }

    // 配置从库
    replicas := make([]gorm.Dialector, len(replicaDSNs))
    for i, dsn := range replicaDSNs {
        replicas[i] = mysql.Open(dsn)
    }

    err = db.Use(dbresolver.Register(dbresolver.Config{
        // Sources: 写库（主库）
        Sources: []gorm.Dialector{mysql.Open(masterDSN)},
        // Replicas: 读库（从库）
        Replicas: replicas,
        // 负载均衡策略：随机轮询
        Policy: dbresolver.RandomPolicy{},
    }).
        // 连接池配置
        SetMaxOpenConns(100).
        SetMaxIdleConns(10).
        SetConnMaxLifetime(time.Hour))

    return db, err
}

// 使用：
// db.Find(&users)          → 自动路由到读库
// db.Create(&user)         → 自动路由到写库
// db.Clauses(dbresolver.Write).Find(&users)  → 强制走写库（读取刚写入的数据）

// ── 方式2：手动实现读写分离（更灵活）─────────────────────────────────────

type DBManager struct {
    write    *gorm.DB
    reads    []*gorm.DB
    counter  atomic.Uint64 // 轮询计数器
}

func NewDBManager(writeDSN string, readDSNs []string) (*DBManager, error) {
    writDB, err := gorm.Open(mysql.Open(writeDSN), &gorm.Config{})
    if err != nil {
        return nil, fmt.Errorf("open write db: %w", err)
    }
    configurePool(writDB)

    readDBs := make([]*gorm.DB, 0, len(readDSNs))
    for _, dsn := range readDSNs {
        rdb, err := gorm.Open(mysql.Open(dsn), &gorm.Config{})
        if err != nil {
            return nil, fmt.Errorf("open read db %s: %w", dsn, err)
        }
        configurePool(rdb)
        readDBs = append(readDBs, rdb)
    }

    return &DBManager{write: writDB, reads: readDBs}, nil
}

// Write 返回写库连接
func (m *DBManager) Write() *gorm.DB {
    return m.write
}

// Read 轮询返回一个读库连接
func (m *DBManager) Read() *gorm.DB {
    if len(m.reads) == 0 {
        return m.write // 无读库时降级到写库
    }
    idx := m.counter.Add(1) % uint64(len(m.reads))
    return m.reads[idx]
}

// ReadRandom 随机返回一个读库
func (m *DBManager) ReadRandom() *gorm.DB {
    if len(m.reads) == 0 {
        return m.write
    }
    return m.reads[rand.Intn(len(m.reads))]
}

func configurePool(db *gorm.DB) {
    sqlDB, _ := db.DB()
    sqlDB.SetMaxOpenConns(50)
    sqlDB.SetMaxIdleConns(10)
    sqlDB.SetConnMaxLifetime(30 * time.Minute)
    sqlDB.SetConnMaxIdleTime(10 * time.Minute)
}

// 在 Service 层使用
type UserService struct {
    dbm *DBManager
}

func (s *UserService) GetUser(ctx context.Context, id int64) (*User, error) {
    var user User
    // 查询走读库
    err := s.dbm.Read().WithContext(ctx).First(&user, id).Error
    return &user, err
}

func (s *UserService) CreateUser(ctx context.Context, user *User) error {
    // 写操作走写库
    return s.dbm.Write().WithContext(ctx).Create(user).Error
}

func (s *UserService) GetUserAfterWrite(ctx context.Context, id int64) (*User, error) {
    var user User
    // 刚写入后立即读取，强制走写库（读自己的写）
    err := s.dbm.Write().WithContext(ctx).First(&user, id).Error
    return &user, err
}
