```go
package main

import (
    "context"
    "database/sql"
    "log/slog"
    "net/http"
    "os/signal"
    "syscall"
    "time"

    "github.com/redis/go-redis/v9"
    "google.golang.org/grpc"
)

type Server struct {
    httpServer  *http.Server
    grpcServer  *grpc.Server
    db          *sql.DB
    redisClient *redis.Client
    logger      *slog.Logger
}

func (s *Server) Run() error {
    // 创建根 context，监听 SIGINT 和 SIGTERM
    rootCtx, stop := signal.NotifyContext(context.Background(),
        syscall.SIGINT,
        syscall.SIGTERM,
        syscall.SIGQUIT,
    )
    defer stop()

    // 1. 启动 HTTP 服务（非阻塞）
    httpErrCh := make(chan error, 1)
    go func() {
        s.logger.Info("HTTP server starting", "addr", s.httpServer.Addr)
        if err := s.httpServer.ListenAndServe(); err != nil && err != http.ErrServerClosed {
            httpErrCh <- err
        }
    }()

    // 2. 启动 gRPC 服务（非阻塞）
    grpcErrCh := make(chan error, 1)
    go func() {
        lis, _ := net.Listen("tcp", ":9090")
        s.logger.Info("gRPC server starting", "addr", ":9090")
        if err := s.grpcServer.Serve(lis); err != nil {
            grpcErrCh <- err
        }
    }()

    // 3. 等待信号或错误
    select {
    case err := <-httpErrCh:
        s.logger.Error("HTTP server error", "error", err)
        return err
    case err := <-grpcErrCh:
        s.logger.Error("gRPC server error", "error", err)
        return err
    case <-rootCtx.Done():
        s.logger.Info("Shutdown signal received, starting graceful shutdown...")
    }

    // 4. 优雅关闭（有序停止）
    return s.shutdown()
}

func (s *Server) shutdown() error {
    // 总关闭超时（应 < k8s terminationGracePeriodSeconds）
    ctx, cancel := context.WithTimeout(context.Background(), 45*time.Second)
    defer cancel()

    // Step 1：停止接收新的 HTTP 请求（立即关闭监听端口）
    s.logger.Info("Step 1: Stopping HTTP server...")
    if err := s.httpServer.Shutdown(ctx); err != nil {
        s.logger.Error("HTTP server shutdown error", "error", err)
    }

    // Step 2：停止接收新的 gRPC 请求
    s.logger.Info("Step 2: Stopping gRPC server...")
    grpcDone := make(chan struct{})
    go func() {
        s.grpcServer.GracefulStop() // 等待正在处理的 RPC 完成
        close(grpcDone)
    }()
    select {
    case <-grpcDone:
        s.logger.Info("gRPC server stopped gracefully")
    case <-ctx.Done():
        s.logger.Warn("gRPC server forced stop (timeout)")
        s.grpcServer.Stop()
    }

    // Step 3：关闭数据库连接池（等待活跃查询完成）
    s.logger.Info("Step 3: Closing database connections...")
    if err := s.db.Close(); err != nil {
        s.logger.Error("DB close error", "error", err)
    }

    // Step 4：关闭 Redis 连接池
    s.logger.Info("Step 4: Closing Redis connections...")
    if err := s.redisClient.Close(); err != nil {
        s.logger.Error("Redis close error", "error", err)
    }

    // Step 5：刷新异步任务（如消息队列、日志缓冲）
    s.logger.Info("Step 5: Flushing async tasks...")
    flushCtx, flushCancel := context.WithTimeout(ctx, 5*time.Second)
    defer flushCancel()
    s.flushAsyncTasks(flushCtx)

    s.logger.Info("Graceful shutdown completed")
    return nil
}

// Kubernetes Deployment 配置
// terminationGracePeriodSeconds: 60   # 总终止时间
// preStop hook: sleep 5               # 等待负载均衡更新路由表
