**Pipeline（管道）：批量发送，一次往返**

```go
// ✅ Pipeline：将多个命令打包一次发送，减少 RTT
func setUserScoresPipeline(ctx context.Context, rdb *redis.Client, scores map[int64]float64) error {
    pipe := rdb.Pipeline()

    for userID, score := range scores {
        key := fmt.Sprintf("score:%d", userID)
        pipe.Set(ctx, key, score, time.Hour)
    }

    // 一次性执行所有命令，返回每个命令的结果
    cmds, err := pipe.Exec(ctx)
    if err != nil {
        // 检查部分失败
        for _, cmd := range cmds {
            if cmd.Err() != nil {
                log.Printf("pipeline cmd failed: %v", cmd.Err())
            }
        }
        return err
    }
    // 1000 个用户 = 1 次网络往返，约 1-2ms
    return nil
}

// TxPipeline：带 MULTI/EXEC 的原子管道（事务）
func atomicUpdate(ctx context.Context, rdb *redis.Client, userID int64, delta int) error {
    key := fmt.Sprintf("counter:%d", userID)

    // TxPipeline 保证原子性（MULTI...EXEC）
    _, err := rdb.TxPipelined(ctx, func(pipe redis.Pipeliner) error {
        pipe.IncrBy(ctx, key, int64(delta))
        pipe.Expire(ctx, key, 24*time.Hour)
        return nil
    })
    return err
}
