**Lua 脚本：服务端原子执行复杂逻辑**

```go
// 场景：原子性地"获取并删除"（GETDEL，Redis 6.2+ 才原生支持）
const getDelScript = `
    local val = redis.call("GET", KEYS[1])
    if val ~= false then
        redis.call("DEL", KEYS[1])
    end
    return val
`

func atomicGetDel(ctx context.Context, rdb *redis.Client, key string) (string, error) {
    result, err := rdb.Eval(ctx, getDelScript, []string{key}).Result()
    if err == redis.Nil {
        return "", nil
    }
    if err != nil {
        return "", err
    }
    return result.(string), nil
}

// 场景：原子性地限流计数（滑动窗口）
const slidingWindowScript = `
    local key = KEYS[1]
    local now = tonumber(ARGV[1])
    local window = tonumber(ARGV[2])
    local limit = tonumber(ARGV[3])

    -- 清除窗口外的记录
    redis.call("ZREMRANGEBYSCORE", key, 0, now - window)

    -- 统计当前窗口内的请求数
    local count = redis.call("ZCARD", key)

    if count < limit then
        -- 允许请求，记录时间戳
        redis.call("ZADD", key, now, now)
        redis.call("EXPIRE", key, math.ceil(window / 1000))
        return 1  -- 允许
    end
    return 0  -- 拒绝
`

func slidingWindowRateLimit(ctx context.Context, rdb *redis.Client, key string, windowMs, limit int64) (bool, error) {
    now := time.Now().UnixMilli()
    result, err := rdb.Eval(ctx, slidingWindowScript,
        []string{key},
        now, windowMs, limit,
    ).Int()
    if err != nil {
        return false, err
    }
    return result == 1, nil
}
