package proxy

import (
    "fmt"
    "log/slog"
    "net/http"
    "net/http/httputil"
    "net/url"
    "strings"
    "time"

    "github.com/gin-gonic/gin"
)

// ProxyConfig 代理配置
type ProxyConfig struct {
    Target      string            // 目标服务地址
    PathPrefix  string            // 匹配的路径前缀
    StripPrefix string            // 转发前去除的前缀
    Headers     map[string]string // 附加请求头
}

// NewReverseProxy 创建反向代理 Handler
func NewReverseProxy(cfg ProxyConfig, logger *slog.Logger) (http.Handler, error) {
    target, err := url.Parse(cfg.Target)
    if err != nil {
        return nil, fmt.Errorf("invalid proxy target %q: %w", cfg.Target, err)
    }

    proxy := httputil.NewSingleHostReverseProxy(target)

    // 自定义 Transport（配置连接池）
    proxy.Transport = &http.Transport{
        MaxIdleConnsPerHost: 20,
        IdleConnTimeout:     90 * time.Second,
        TLSHandshakeTimeout: 10 * time.Second,
    }

    // 自定义 Director：修改转发前的请求
    originalDirector := proxy.Director
    proxy.Director = func(req *http.Request) {
        originalDirector(req) // 先执行默认 director（设置 host 等）

        // 路径重写：去除前缀
        if cfg.StripPrefix != "" {
            req.URL.Path = strings.TrimPrefix(req.URL.Path, cfg.StripPrefix)
            if req.URL.Path == "" {
                req.URL.Path = "/"
            }
            req.URL.RawPath = strings.TrimPrefix(req.URL.RawPath, cfg.StripPrefix)
        }

        // 注入附加请求头
        for k, v := range cfg.Headers {
            req.Header.Set(k, v)
        }

        // 传递真实客户端 IP
        req.Header.Set("X-Forwarded-For", req.RemoteAddr)
        req.Header.Set("X-Real-IP", req.RemoteAddr)
        req.Header.Set("X-Forwarded-Host", req.Host)

        logger.Debug("proxying request",
            "method", req.Method,
            "target", req.URL.String(),
        )
    }

    // 自定义错误处理
    proxy.ErrorHandler = func(w http.ResponseWriter, r *http.Request, err error) {
        logger.Error("proxy error",
            "target", cfg.Target,
            "path", r.URL.Path,
            "error", err,
        )
        http.Error(w, "Bad Gateway", http.StatusBadGateway)
    }

    // 响应修改（如去除内部响应头）
    proxy.ModifyResponse = func(resp *http.Response) error {
        resp.Header.Del("X-Internal-Token")
        resp.Header.Set("X-Proxied-By", "myapp-gateway")
        return nil
    }

    return proxy, nil
}

// ProxyMiddleware Gin 代理中间件
func ProxyMiddleware(cfg ProxyConfig, logger *slog.Logger) gin.HandlerFunc {
    proxy, err := NewReverseProxy(cfg, logger)
    if err != nil {
        panic(err)
    }
    return func(c *gin.Context) {
        proxy.ServeHTTP(c.Writer, c.Request)
        c.Abort() // 不继续执行后续 Handler
    }
}

// 使用示例：API 网关路由
func SetupGateway() *gin.Engine {
    r := gin.New()
    logger := slog.Default()

    // /api/users/* → 用户服务
    r.Any("/api/users/*path", ProxyMiddleware(ProxyConfig{
        Target:      "http://user-service:8081",
        StripPrefix: "/api/users",
        Headers: map[string]string{
            "X-Service-Name": "api-gateway",
        },
    }, logger))

    // /api/orders/* → 订单服务
    r.Any("/api/orders/*path", ProxyMiddleware(ProxyConfig{
        Target:      "http://order-service:8082",
        StripPrefix: "/api/orders",
    }, logger))

    return r
}
