**两种负载均衡模式对比：**

| 维度       | 客户端负载均衡           | 服务端负载均衡（LB Proxy） |
| ---------- | ------------------------ | -------------------------- |
| 实现位置   | 调用方（客户端 SDK）     | 独立代理（Nginx/Envoy）    |
| 延迟       | 低（直连）               | 较高（多一跳）             |
| 故障转移   | 快（客户端感知）         | 依赖代理检测               |
| 运维复杂度 | 高（每个客户端都需维护） | 低（集中管理）             |
| 典型方案   | gRPC + Consul/etcd       | Nginx、Envoy、APISIX       |

**gRPC 客户端负载均衡实现（基于 Consul 服务发现）：**

```go
package lb

import (
    "context"
    "fmt"
    "sync"
    "sync/atomic"
    "time"

    "google.golang.org/grpc"
    "google.golang.org/grpc/balancer/roundrobin"
    "google.golang.org/grpc/resolver"
)

// ── 方式1：gRPC 内置 round_robin + 自定义 Resolver ─────────────────────

// consulResolver 实现 gRPC resolver.Resolver 接口
type consulResolver struct {
    cc          resolver.ClientConn
    serviceName string
    consul      *consulapi.Client
    done        chan struct{}
}

func (r *consulResolver) start() {
    go r.watch()
}

func (r *consulResolver) watch() {
    var lastIndex uint64
    for {
        select {
        case <-r.done:
            return
        default:
        }

        // 长轮询 Consul（有变更时立即返回，无变更则阻塞 waitTime）
        entries, meta, err := r.consul.Health().Service(
            r.serviceName, "", true,
            &consulapi.QueryOptions{
                WaitIndex: lastIndex,
                WaitTime:  30 * time.Second,
            },
        )
        if err != nil {
            time.Sleep(time.Second) // 出错后短暂等待重试
            continue
        }

        lastIndex = meta.LastIndex

        // 转换为 gRPC 地址列表
        addrs := make([]resolver.Address, 0, len(entries))
        for _, entry := range entries {
            addr := fmt.Sprintf("%s:%d", entry.Service.Address, entry.Service.Port)
            addrs = append(addrs, resolver.Address{
                Addr:       addr,
                ServerName: entry.Service.ID,
            })
        }

        // 通知 gRPC 更新地址列表
        r.cc.UpdateState(resolver.State{Addresses: addrs})
    }
}

func (r *consulResolver) ResolveNow(resolver.ResolveNowOptions) {}
func (r *consulResolver) Close() { close(r.done) }

// consulResolverBuilder 实现 resolver.Builder
type consulResolverBuilder struct {
    consul *consulapi.Client
}

func (b *consulResolverBuilder) Build(target resolver.Target, cc resolver.ClientConn, opts resolver.BuildOptions) (resolver.Resolver, error) {
    r := &consulResolver{
        cc:          cc,
        serviceName: target.Endpoint(),
        consul:      b.consul,
        done:        make(chan struct{}),
    }
    r.start()
    return r, nil
}

func (b *consulResolverBuilder) Scheme() string { return "consul" }

// 注册并使用
func init() {
    consulClient, _ := consulapi.NewClient(consulapi.DefaultConfig())
    resolver.Register(&consulResolverBuilder{consul: consulClient})
}

func NewUserServiceClient() (pb.UserServiceClient, error) {
    conn, err := grpc.Dial(
        "consul:///user-service", // consul:///<service-name>
        grpc.WithDefaultServiceConfig(fmt.Sprintf(`{
            "loadBalancingConfig": [{"%s":{}}]
        }`, roundrobin.Name)), // 轮询策略
        grpc.WithInsecure(),
    )
    if err != nil {
        return nil, err
    }
    return pb.NewUserServiceClient(conn), nil
}

// ── 方式2：手动轮询（简单场景）──────────────────────────────────────────

type RoundRobinPool struct {
    mu      sync.RWMutex
    conns   []*grpc.ClientConn
    counter atomic.Uint64
}

func NewRoundRobinPool(addrs []string) (*RoundRobinPool, error) {
    pool := &RoundRobinPool{
        conns: make([]*grpc.ClientConn, 0, len(addrs)),
    }
    for _, addr := range addrs {
        conn, err := grpc.Dial(addr, grpc.WithInsecure())
        if err != nil {
            pool.Close()
            return nil, err
        }
        pool.conns = append(pool.conns, conn)
    }
    return pool, nil
}

func (p *RoundRobinPool) Get() *grpc.ClientConn {
    p.mu.RLock()
    defer p.mu.RUnlock()
    if len(p.conns) == 0 {
        return nil
    }
    idx := p.counter.Add(1) % uint64(len(p.conns))
    return p.conns[idx]
}

func (p *RoundRobinPool) Close() {
    for _, c := range p.conns {
        c.Close()
    }
}
```

```go
package handler

import (
    "crypto/md5"
    "fmt"
    "io"
    "net/http"
    "os"
    "path/filepath"
    "sort"
    "strconv"

    "github.com/gin-gonic/gin"
)

// ── 普通文件上传（< 10MB）─────────────────────────────────────────────────

func UploadFile(c *gin.Context) {
    // 限制请求体大小（防止内存溢出）
    c.Request.Body = http.MaxBytesReader(c.Writer, c.Request.Body, 10<<20) // 10MB

    file, header, err := c.Request.FormFile("file")
    if err != nil {
        c.JSON(http.StatusBadRequest, gin.H{"error": "get file failed: " + err.Error()})
        return
    }
    defer file.Close()

    // 验证文件类型（通过 magic bytes，不信任 Content-Type）
    buf := make([]byte, 512)
    n, _ := file.Read(buf)
    contentType := http.DetectContentType(buf[:n])
    allowedTypes := map[string]string{
        "image/jpeg": ".jpg",
        "image/png":  ".png",
        "image/gif":  ".gif",
        "application/pdf": ".pdf",
    }
    ext, allowed := allowedTypes[contentType]
    if !allowed {
        c.JSON(http.StatusBadRequest, gin.H{"error": "unsupported file type: " + contentType})
        return
    }

    // 重置到文件头（已读取了 512 字节用于类型检测）
    file.Seek(0, io.SeekStart)

    // 计算 MD5（用于去重）
    hasher := md5.New()
    size, _ := io.Copy(hasher, file)
    checksum := fmt.Sprintf("%x", hasher.Sum(nil))
    file.Seek(0, io.SeekStart)

    // 保存文件
    filename := fmt.Sprintf("%s%s", checksum, ext)
    dst := filepath.Join("uploads", filename)
    if err := os.MkdirAll("uploads", 0755); err != nil {
        c.JSON(http.StatusInternalServerError, gin.H{"error": "create dir failed"})
        return
    }

    out, err := os.Create(dst)
    if err != nil {
        c.JSON(http.StatusInternalServerError, gin.H{"error": "create file failed"})
        return
    }
    defer out.Close()

    if _, err := io.Copy(out, file); err != nil {
        c.JSON(http.StatusInternalServerError, gin.H{"error": "save file failed"})
        return
    }

    c.JSON(http.StatusOK, gin.H{
        "filename": header.Filename,
        "size":     size,
        "checksum": checksum,
        "url":      "/files/" + filename,
    })
}

// ── 分片上传（大文件）────────────────────────────────────────────────────

// UploadChunk 上传单个分片
// POST /upload/chunk
// Form: file=<binary>, upload_id=<string>, chunk_index=<int>, total_chunks=<int>
func UploadChunk(c *gin.Context) {
    uploadID := c.PostForm("upload_id")
    chunkIndexStr := c.PostForm("chunk_index")
    totalChunksStr := c.PostForm("total_chunks")

    chunkIndex, err := strconv.Atoi(chunkIndexStr)
    if err != nil || chunkIndex < 0 {
        c.JSON(http.StatusBadRequest, gin.H{"error": "invalid chunk_index"})
        return
    }
    totalChunks, _ := strconv.Atoi(totalChunksStr)

    // 获取分片数据
    chunk, _, err := c.Request.FormFile("file")
    if err != nil {
        c.JSON(http.StatusBadRequest, gin.H{"error": "get chunk failed"})
        return
    }
    defer chunk.Close()

    // 保存分片到临时目录
    chunkDir := filepath.Join("tmp", "chunks", uploadID)
    if err := os.MkdirAll(chunkDir, 0755); err != nil {
        c.JSON(http.StatusInternalServerError, gin.H{"error": "create chunk dir"})
        return
    }

    chunkPath := filepath.Join(chunkDir, fmt.Sprintf("chunk_%05d", chunkIndex))
    out, err := os.Create(chunkPath)
    if err != nil {
        c.JSON(http.StatusInternalServerError, gin.H{"error": "save chunk"})
        return
    }
    defer out.Close()
    io.Copy(out, chunk)

    // 检查是否所有分片已上传
    entries, _ := os.ReadDir(chunkDir)
    if len(entries) == totalChunks {
        // 合并分片
        finalPath := filepath.Join("uploads", uploadID)
        if err := mergeChunks(chunkDir, finalPath, totalChunks); err != nil {
            c.JSON(http.StatusInternalServerError, gin.H{"error": "merge chunks"})
            return
        }
        os.RemoveAll(chunkDir) // 清理临时分片

        c.JSON(http.StatusOK, gin.H{
            "status":    "completed",
            "upload_id": uploadID,
            "url":       "/files/" + uploadID,
        })
        return
    }

    c.JSON(http.StatusOK, gin.H{
        "status":        "chunk_received",
        "chunk_index":   chunkIndex,
        "received":      len(entries),
        "total_chunks":  totalChunks,
    })
}

func mergeChunks(chunkDir, dstPath string, totalChunks int) error {
    dst, err := os.Create(dstPath)
    if err != nil {
        return err
    }
    defer dst.Close()

    // 按序合并
    for i := 0; i < totalChunks; i++ {
        chunkPath := filepath.Join(chunkDir, fmt.Sprintf("chunk_%05d", i))
        chunk, err := os.Open(chunkPath)
        if err != nil {
            return fmt.Errorf("open chunk %d: %w", i, err)
        }
        _, err = io.Copy(dst, chunk)
        chunk.Close()
        if err != nil {
            return fmt.Errorf("copy chunk %d: %w", i, err)
        }
    }
    return nil
}

// 路由注册
func RegisterUploadRoutes(r *gin.Engine) {
    upload := r.Group("/upload")
    {
        upload.POST("/single", UploadFile)
        upload.POST("/chunk", UploadChunk)
    }
}
