**OpenTelemetry 核心概念：**

```
Trace（一次完整请求链路）
  └── Span A：API Gateway 接收请求
        ├── Span B：调用 User Service（子 Span）
        │     └── Span D：User Service 查询 DB
        └── Span C：调用 Order Service（子 Span）
              └── Span E：Order Service 查询 Redis

每个 Span 包含：
- TraceID（全链路唯一）
- SpanID（当前 Span 唯一）
- ParentSpanID（父 Span ID）
- 开始/结束时间
- 属性（Tags）：http.method, db.query, error 等
- 事件（Events）：时间点上的日志
```

**初始化 OpenTelemetry（发送到 Jaeger）：**

```go
package telemetry

import (
    "context"

    "go.opentelemetry.io/otel"
    "go.opentelemetry.io/otel/exporters/otlp/otlptrace/otlptracehttp"
    "go.opentelemetry.io/otel/propagation"
    "go.opentelemetry.io/otel/sdk/resource"
    sdktrace "go.opentelemetry.io/otel/sdk/trace"
    semconv "go.opentelemetry.io/otel/semconv/v1.21.0"
    "go.opentelemetry.io/otel/trace"
)

func InitTracer(serviceName, endpoint string) (func(context.Context) error, error) {
    // 创建 OTLP HTTP 导出器（发送到 Jaeger/Zipkin/Tempo）
    exporter, err := otlptracehttp.New(context.Background(),
        otlptracehttp.WithEndpoint(endpoint),
        otlptracehttp.WithInsecure(),
    )
    if err != nil {
        return nil, err
    }

    // 资源属性（服务基本信息）
    res := resource.NewWithAttributes(
        semconv.SchemaURL,
        semconv.ServiceName(serviceName),
        semconv.ServiceVersion(Version),
        semconv.DeploymentEnvironment(Env),
    )

    // TracerProvider
    tp := sdktrace.NewTracerProvider(
        sdktrace.WithBatcher(exporter),    // 批量导出（生产推荐）
        sdktrace.WithResource(res),
        sdktrace.WithSampler(
            // 生产环境采样率（全量采集开销大）
            sdktrace.ParentBased(sdktrace.TraceIDRatioBased(0.1)), // 10% 采样
        ),
    )

    // 设置全局 TracerProvider 和 Propagator
    otel.SetTracerProvider(tp)
    otel.SetTextMapPropagator(propagation.NewCompositeTextMapPropagator(
        propagation.TraceContext{}, // W3C TraceContext 标准
        propagation.Baggage{},
    ))

    // 返回 shutdown 函数
    return tp.Shutdown, nil
}
```

**Gin 集成 OpenTelemetry 中间件：**

```go
package middleware

import (
    "github.com/gin-gonic/gin"
    "go.opentelemetry.io/contrib/instrumentation/github.com/gin-gonic/gin/otelgin"
    "go.opentelemetry.io/otel"
    "go.opentelemetry.io/otel/attribute"
    "go.opentelemetry.io/otel/codes"
    "go.opentelemetry.io/otel/trace"
)

var tracer = otel.Tracer("myapp/handler")

// 使用官方 otelgin 中间件（自动处理 Span 创建和 Context 传播）
func SetupRouter() *gin.Engine {
    r := gin.New()
    r.Use(otelgin.Middleware("user-service"))
    return r
}

// 在 Handler 中创建子 Span
func getUserHandler(c *gin.Context) {
    // 从 Gin context 提取 trace context
    ctx := c.Request.Context()

    // 创建子 Span（自动关联到父 Span）
    ctx, span := tracer.Start(ctx, "getUserHandler",
        trace.WithAttributes(
            attribute.String("user.id", c.Param("id")),
        ),
    )
    defer span.End()

    user, err := userService.GetUser(ctx, c.Param("id"))
    if err != nil {
        // 记录错误到 Span
        span.RecordError(err)
        span.SetStatus(codes.Error, err.Error())
        c.JSON(500, gin.H{"error": err.Error()})
        return
    }

    // 添加自定义属性
    span.SetAttributes(
        attribute.String("user.name", user.Name),
        attribute.String("user.role", user.Role),
    )

    c.JSON(200, user)
}
