**跨服务 Context 传播（HTTP）：**

```go
// 发送 HTTP 请求时注入 Trace 信息
func callUserService(ctx context.Context, userID string) (*User, error) {
    req, _ := http.NewRequestWithContext(ctx, "GET",
        "http://user-service/users/"+userID, nil)

    // 将当前 Span 的 TraceID/SpanID 注入到 HTTP Header
    // 注入后 Header 包含：traceparent: 00-{traceID}-{spanID}-01
    otel.GetTextMapPropagator().Inject(ctx, propagation.HeaderCarrier(req.Header))

    resp, err := http.DefaultClient.Do(req)
    // ...
}

// 接收 HTTP 请求时提取 Trace 信息
func extractTraceFromHTTP(r *http.Request) context.Context {
    // 从 Header 提取上游传来的 Trace 信息
    ctx := otel.GetTextMapPropagator().Extract(
        r.Context(),
        propagation.HeaderCarrier(r.Header),
    )
    return ctx // ctx 中包含了上游的 Span 信息，新建的 Span 会自动成为其子 Span
}
